'use client';

import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export const useStore = create(
  persist(
    (set, get) => ({
      members: [],
      transactions: [],

      addMember: (data) => 
        set(state => ({
          members: [
            ...state.members,
            {
              id: Date.now().toString(),
              name: data.name.trim(),
              phone: data.phone?.trim() || '',
              address: data.address?.trim() || '',
              avatar: data.avatar || `https://i.pravatar.cc/150?u=${encodeURIComponent(data.name)}`,
              totalDonated: 0,
              totalReceived: 0,
            }
          ]
        })),

      addTransaction: (tx) =>
        set(state => {
          const newTx = {
            ...tx,
            id: Date.now().toString(),
            date: new Date().toISOString().split('T')[0]
          };

          let updatedMembers = [...state.members];

          if (tx.type === 'donation') {
            // দাতার totalDonated বাড়াও (নাম case-insensitive + trim করে মিলানো)
            if (tx.donorName) {
              const donorNameLower = tx.donorName.trim().toLowerCase();
              updatedMembers = updatedMembers.map(member =>
                member.name.trim().toLowerCase() === donorNameLower
                  ? { ...member, totalDonated: (member.totalDonated || 0) + Number(tx.amount || 0) }
                  : member
              );
            }

            // গ্রহীতার totalReceived বাড়াও
            if (tx.receiverName) {
              const receiverNameLower = tx.receiverName.trim().toLowerCase();
              updatedMembers = updatedMembers.map(member =>
                member.name.trim().toLowerCase() === receiverNameLower
                  ? { ...member, totalReceived: (member.totalReceived || 0) + Number(tx.amount || 0) }
                  : member
              );
            }
          }

          return {
            transactions: [...state.transactions, newTx],
            members: updatedMembers
          };
        }),

      updateMemberTotals: (memberId, donated = 0, received = 0) =>
        set(state => ({
          members: state.members.map(m =>
            m.id === memberId
              ? {
                  ...m,
                  totalDonated: (m.totalDonated || 0) + donated,
                  totalReceived: (m.totalReceived || 0) + received
                }
              : m
          )
        })),

      deleteTransaction: (id) =>
        set(state => ({
          transactions: state.transactions.filter(t => t.id !== id)
        })),

      getMemberDonations: (memberId) =>
        get().transactions.filter(t => t.type === 'donation' && (t.donorId === memberId || t.receiverId === memberId))
    }),
    { name: 'group-fund-v3' }
  )
);